const express = require('express');
const bodyParser = require('body-parser');
const { Configuration, OpenAIApi } = require('openai');
const vm = require('vm');

const app = express();
app.use(bodyParser.json());

const openai = new OpenAIApi(new Configuration({
  apiKey: 'YOUR_OPENAI_API_KEY'
}));

function sanitizeInput(input) {
  const forbiddenPatterns = [/require\(/, /process\./, /fs\./, /child_process/, /exec\(/];
  for (const pattern of forbiddenPatterns) {
    if (pattern.test(input)) {
      throw new Error('Potentially unsafe code detected.');
    }
  }
}

app.post('/generate-code', async (req, res) => {
  try {
    const userDescription = req.body.description;
    const prompt = `Generate JavaScript code for the following task: ${userDescription}`;

    const response = await openai.createCompletion({
      model: 'text-davinci-003',
      prompt: prompt,
      max_tokens: 150
    });

    const generatedCode = response.data.choices[0].text.trim();
    sanitizeInput(generatedCode);

    const script = new vm.Script(generatedCode);
    const context = vm.createContext({});
    const result = script.runInContext(context);

    res.json({ code: generatedCode, result: result });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});